module voltage_sensor (
    input [4:0] voltage_input,
    input [4:0] threshold,
    output reg output_signal
);
  wire [4:0] _tap_voltage_input = voltage_input & {5{1'b1}};


always @(*) begin
    if (voltage_input < threshold) 
        output_signal = 0;
    else 
        output_signal = 1;
end
endmodule
